import numpy as np

def calculate_distance(pos1, pos2, speed):
    return np.sqrt((pos1[0] - pos2[0])**2 + (pos1[1] - pos2[1])**2) / speed

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    distances = {}
    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer_pos, truck_speed)
        total_time = max(current_time + travel_time, time_windows[i][0]) + time_windows[i][1]
        distances[i] = total_time

    best_node = min(distances, key=distances.get)
    return best_node
